questions.questionText:
다음 C 언어 프로그램이 실행되었을 때의 결과는?

#include <stdio.h>

int main(void) {
    int a = 3, b = 4, c = 2;
    int r1, r2, r3;
    r1 = b <= 4 || c == 2;
    r2 = (a > 0) && (b < 5);
    r3 = !c;
    printf("%d", r1 + r2 + r3);
    return 0;
}

